def glob_match(pattern: str, text: str) -> bool:
    # Parse pattern into tokens
    tokens = []
    i = 0
    n = len(pattern)

    while i < n:
        c = pattern[i]
        if c == '\\':
            if i + 1 >= n:
                raise ValueError("Trailing backslash in pattern")
            tokens.append(('literal', pattern[i + 1]))
            i += 2
        elif c == '*':
            tokens.append(('star',))
            i += 1
        elif c == '?':
            tokens.append(('any',))
            i += 1
        elif c == '[':
            i += 1
            if i >= n:
                raise ValueError("Unterminated character class")
            negated = False
            if i < n and pattern[i] in ('!', '^'):
                negated = True
                i += 1
            if i >= n:
                raise ValueError("Unterminated character class")

            chars = set()
            first = True
            while i < n:
                # ] closes the class only if it's not the first char
                if pattern[i] == ']' and not first:
                    break
                if pattern[i] == '\\':
                    if i + 1 >= n:
                        raise ValueError("Trailing backslash inside character class")
                    chars.add(pattern[i + 1])
                    i += 2
                elif (i + 2 < n
                      and pattern[i + 1] == '-'
                      and pattern[i + 2] != ']'):
                    # Range like a-z
                    start, end = pattern[i], pattern[i + 2]
                    if ord(start) > ord(end):
                        raise ValueError(
                            f"Invalid range [{start}-{end}] in character class")
                    for code in range(ord(start), ord(end) + 1):
                        chars.add(chr(code))
                    i += 3
                else:
                    chars.add(pattern[i])
                    i += 1
                first = False

            if i >= n:
                raise ValueError("Unterminated character class")

            tokens.append(('class', frozenset(chars), negated))
            i += 1  # skip closing ]
        else:
            tokens.append(('literal', c))
            i += 1

    # Match tokens against text using memoised recursion
    tlen = len(tokens)
    slen = len(text)
    memo = {}

    def match(ti: int, si: int) -> bool:
        if (ti, si) in memo:
            return memo[(ti, si)]

        if ti == tlen:
            result = si == slen
            memo[(ti, si)] = result
            return result

        tok = tokens[ti]

        if tok[0] == 'star':
            # Collapse consecutive stars
            nti = ti + 1
            while nti < tlen and tokens[nti][0] == 'star':
                nti += 1
            result = False
            for si2 in range(si, slen + 1):
                if match(nti, si2):
                    result = True
                    break
        elif tok[0] == 'literal':
            if si < slen and text[si] == tok[1]:
                result = match(ti + 1, si + 1)
            else:
                result = False
        elif tok[0] == 'any':
            result = si < slen and match(ti + 1, si + 1)
        elif tok[0] == 'class':
            chars, negated = tok[1], tok[2]
            if si < slen:
                in_class = text[si] in chars
                if negated:
                    in_class = not in_class
                result = in_class and match(ti + 1, si + 1)
            else:
                result = False
        else:
            result = False

        memo[(ti, si)] = result
        return result

    return match(0, 0)

