def glob_match(pattern: str, text: str) -> bool:
    from functools import lru_cache

    n = len(pattern)
    m = len(text)

    # Validate pattern first
    i = 0
    while i < n:
        c = pattern[i]
        if c == '\\':
            if i + 1 >= n:
                raise ValueError("Trailing backslash in pattern")
            i += 2
        elif c == '[':
            j = i + 1
            if j >= n:
                raise ValueError("Unterminated character class")
            # skip negation
            if j < n and pattern[j] in ('!', '^'):
                j += 1
            # ']' as first char is literal
            if j < n and pattern[j] == ']':
                j += 1
            found = False
            while j < n:
                if pattern[j] == '\\':
                    if j + 1 >= n:
                        raise ValueError("Trailing backslash in pattern")
                    j += 2
                elif pattern[j] == ']':
                    found = True
                    j += 1
                    break
                else:
                    j += 1
            if not found:
                raise ValueError("Unterminated character class")
            i = j
        else:
            i += 1

    def char_in_class(ch, pi):
        """Match ch against character class body starting at pi (after '[').
        Returns (matched: bool, next_pi: int pointing after ']')."""
        negate = False
        if pi < n and pattern[pi] in ('!', '^'):
            negate = True
            pi += 1

        matched = False
        first = True

        while pi < n:
            # ']' ends the class unless it's the first character
            if pattern[pi] == ']' and not first:
                break

            first = False

            # Get one character (handle escape)
            if pattern[pi] == '\\':
                c1 = pattern[pi + 1]
                pi += 2
            else:
                c1 = pattern[pi]
                pi += 1

            # Check for range c1-c2 (only if '-' is not followed by ']')
            if pi + 1 < n and pattern[pi] == '-' and pattern[pi + 1] != ']':
                pi += 1  # skip '-'
                if pattern[pi] == '\\':
                    c2 = pattern[pi + 1]
                    pi += 2
                else:
                    c2 = pattern[pi]
                    pi += 1
                if c1 <= ch <= c2:
                    matched = True
            else:
                if ch == c1:
                    matched = True

        # pi is now at ']'
        pi += 1  # skip ']'

        if negate:
            matched = not matched

        return matched, pi

    @lru_cache(maxsize=None)
    def dp(pi, ti):
        # Both exhausted
        if pi == n:
            return ti == m

        c = pattern[pi]

        if c == '\\':
            literal = pattern[pi + 1]
            if ti < m and text[ti] == literal:
                return dp(pi + 2, ti + 1)
            return False

        elif c == '*':
            # Match zero or more characters; try all lengths
            for k in range(ti, m + 1):
                if dp(pi + 1, k):
                    return True
            return False

        elif c == '?':
            if ti < m:
                return dp(pi + 1, ti + 1)
            return False

        elif c == '[':
            if ti >= m:
                return False
            ch = text[ti]
            matched, next_pi = char_in_class(ch, pi + 1)
            if matched:
                return dp(next_pi, ti + 1)
            return False

        else:
            # Literal character
            if ti < m and text[ti] == c:
                return dp(pi + 1, ti + 1)
            return False

    result = dp(0, 0)
    dp.cache_clear()
    return result
